package terminal

import (
	"testing"

	"github.com/jandedobbeleer/oh-my-posh/src/color"
	"github.com/jandedobbeleer/oh-my-posh/src/shell"
)

// BenchmarkWriteAnchors benchmarks the writer with realistic anchor-heavy input
// containing color overrides, bold, and a hyperlink — 6+ anchor tokens total.
func BenchmarkWriteAnchors(b *testing.B) {
	Init(shell.PWSH)
	Colors = &color.Defaults{}
	colors := &color.Set{Foreground: "white", Background: "blue"}
	input := `<#CAF25B>src</> / <red,blue>main</> <b>oh-my-posh</b> <u>feat</u> <LINK>https://example.com<TEXT>link</TEXT></LINK>`
	b.ReportAllocs()
	for b.Loop() {
		CurrentColors = colors
		ParentColors = nil
		Write(colors.Background, colors.Foreground, input)
		_, _ = String()
	}
}

// BenchmarkWritePlainASCII benchmarks the writer with 80 chars of plain ASCII — no anchors.
func BenchmarkWritePlainASCII(b *testing.B) {
	Init(shell.PWSH)
	Colors = &color.Defaults{}
	colors := &color.Set{Foreground: "white", Background: "blue"}
	input := "this is a plain eighty character ascii string with no color anchors whatsoever!!"
	b.ReportAllocs()
	for b.Loop() {
		CurrentColors = colors
		ParentColors = nil
		Write(colors.Background, colors.Foreground, input)
		_, _ = String()
	}
}

package prompt

import (
	"testing"

	"github.com/jandedobbeleer/oh-my-posh/src/cache"
	"github.com/jandedobbeleer/oh-my-posh/src/color"
	"github.com/jandedobbeleer/oh-my-posh/src/config"
	"github.com/jandedobbeleer/oh-my-posh/src/maps"
	"github.com/jandedobbeleer/oh-my-posh/src/runtime"
	"github.com/jandedobbeleer/oh-my-posh/src/shell"
	"github.com/jandedobbeleer/oh-my-posh/src/template"
	"github.com/jandedobbeleer/oh-my-posh/src/terminal"
)

// newBenchEngine builds a minimal Engine with two left-aligned plain-text segments
// in one block, using a real (but empty) runtime.Terminal so no network/git calls
// are made. Template and terminal state are reset each call so iterations are
// independent.
func newBenchEngine() *Engine {
	flags := &runtime.Flags{
		Shell:     shell.GENERIC,
		IsPrimary: true,
	}

	env := &runtime.Terminal{}
	env.Init(flags)

	template.Cache = &cache.Template{
		SimpleTemplate: cache.SimpleTemplate{
			Shell: shell.GENERIC,
		},
		Segments: maps.NewConcurrent[any](),
	}
	template.Init(env, nil, nil)

	terminal.Init(shell.GENERIC)
	terminal.Colors = &color.Defaults{}

	cfg := &config.Config{
		Blocks: []*config.Block{
			{
				Type:      config.Prompt,
				Alignment: config.Left,
				Segments: []*config.Segment{
					{
						Type:       "text",
						Template:   "hello",
						Foreground: "white",
						Background: "blue",
					},
					{
						Type:       "text",
						Template:   "world",
						Foreground: "white",
						Background: "cyan",
					},
				},
			},
		},
	}

	return &Engine{
		Config: cfg,
		Env:    env,
	}
}

// BenchmarkEnginePrimary measures a full engine.Primary() call with a small
// deterministic config — no real git/network — using a plain shell.
func BenchmarkEnginePrimary(b *testing.B) {
	b.ReportAllocs()
	for b.Loop() {
		eng := newBenchEngine()
		eng.Primary()
		eng.string() // flush prompt builder
	}
}

